@* Displays a single task with move buttons *@

<div class="task-card">
    <div class="task-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-meta">
        <span class="task-assignee">👤 @Task.Assignee</span>
        <span class="task-due">📅 @Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn btn-sm btn-move" @onclick="OnMoveLeftClick" disabled="@IsMoving">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn btn-sm btn-move" @onclick="OnMoveRightClick" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }

    private bool IsMoving;

    private async System.Threading.Tasks.Task OnMoveLeftClick()
    {
        IsMoving = true;
        await OnMoveLeft.InvokeAsync(Task);
        IsMoving = false;
    }

    private async System.Threading.Tasks.Task OnMoveRightClick()
    {
        IsMoving = true;
        await OnMoveRight.InvokeAsync(Task);
        IsMoving = false;
    }
}

@* Inline form to create a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <div class="form-group">
            <input type="text" class="form-input" placeholder="Title" @bind="Title" />
        </div>
        <div class="form-group">
            <input type="text" class="form-input" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="form-group">
            <select class="form-input" @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="form-group">
            <input type="date" class="form-input" @bind="DueDate" />
        </div>
        @if (!string.IsNullOrEmpty(validationError))
        {
            <div class="form-error">@validationError</div>
        }
        <div class="form-actions">
            <button class="btn btn-save" @onclick="Save" disabled="@IsSaving">Save</button>
            <button class="btn btn-cancel" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = string.Empty;
    private string Assignee = string.Empty;
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);
    private string? validationError;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title) || string.IsNullOrWhiteSpace(Assignee))
        {
            validationError = "Title and Assignee are required.";
            return;
        }

        validationError = null;
        IsSaving = true;
        await OnSave.InvokeAsync((Title, Assignee, Priority, DueDate));
        IsSaving = false;
        IsVisible = false;
        ResetForm();
    }

    private void ResetForm()
    {
        Title = string.Empty;
        Assignee = string.Empty;
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
        validationError = null;
    }
}

@* A single Kanban column displaying its tasks and an add-task form *@

<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="task-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>

    <div class="column-footer">
        <AddTaskForm OnSave="OnAddTask" />
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }
}

@* Search bar for filtering tasks by title *@

<div class="search-bar">
    <input type="text"
           class="form-input search-input"
           placeholder="Search tasks by title…"
           value="@SearchTerm"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTermChanged.InvokeAsync(value);
    }
}

