+@page "/board"
+@rendermode InteractiveServer
+@using sv_0d758fd2191340e293029bbf35c24073.Components.Board
+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+<div class="board-page">
+    @if (isLoading)
+    {
+        <div class="board-loading">Loading board…</div>
+    }
+    else if (errorMessage is not null)
+    {
+        <div class="board-error">
+            <p>@errorMessage</p>
+            <button class="btn" @onclick="LoadTasks">Retry</button>
+        </div>
+    }
+    else
+    {
+        <BoardStats Tasks="allTasks" />
+        <TaskSearchBar @bind-SearchTerm="searchTerm" />
+
+        <div class="kanban-board">
+            <KanbanColumn ColumnName="To Do"
+                          Tasks="GetFiltered("To Do")"
+                          ShowMoveLeft="false"
+                          ShowMoveRight="true"
+                          OnMoveRight="@(t => MoveTask(t, "In Progress"))"
+                          OnAddTask="@(f => AddTask(f, "To Do"))" />
+
+            <KanbanColumn ColumnName="In Progress"
+                          Tasks="GetFiltered("In Progress")"
+                          ShowMoveLeft="true"
+                          ShowMoveRight="true"
+                          OnMoveLeft="@(t => MoveTask(t, "To Do"))"
+                          OnMoveRight="@(t => MoveTask(t, "Done"))"
+                          OnAddTask="@(f => AddTask(f, "In Progress"))" />
+
+            <KanbanColumn ColumnName="Done"
+                          Tasks="GetFiltered("Done")"
+                          ShowMoveLeft="true"
+                          ShowMoveRight="false"
+                          OnMoveLeft="@(t => MoveTask(t, "In Progress"))"
+                          OnAddTask="@(f => AddTask(f, "Done"))" />
+        </div>
+    }
+</div>
+
+@code {
+    private List<TaskItem> allTasks = new();
+    private string searchTerm = string.Empty;
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasks();
+    }
+
+    private async Task LoadTasks()
+    {
+        isLoading = true;
+        errorMessage = null;
+
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load tasks: {ex.Message}";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private List<TaskItem> GetFiltered(string status)
+    {
+        var query = allTasks.Where(t => t.Status == status);
+
+        if (!string.IsNullOrWhiteSpace(searchTerm))
+        {
+            query = query.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
+        }
+
+        return query.ToList();
+    }
+
+    private async Task MoveTask(TaskItem task, string newStatus)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
+            var index = allTasks.FindIndex(t => t.Id == task.Id);
+            if (index >= 0)
+            {
+                allTasks[index] = task with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+    }
+
+    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) form, string status)
+    {
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(form.Title, form.Assignee, form.Priority, form.DueDate);
+            allTasks.Add(created with { Status = status });
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to create task: {ex.Message}";
+        }
+    }
+}
